    gateway_intent: d._intent,
    gateway_entities: d._entities,
    payload: d.payload
  },
  risk_level: d._risk_level || "medium",
  amount: d._entities?.amount || 0,
  currency: "BRL",
  metadata: d.metadata || {}
};
return [{ json: out }];

const d = $input.first().json;
const out = {
  runtime_mode: d.runtime_mode,
  correlation_id: d.correlation_id,
  request_id: d.request_id,
  source: "gateway",
  workflow: "CORE - Gateway Supervisor",
  agent: "supervisor",
  module: "core",
  failed_node: "Gateway classified audit_error intent",
  error_message: d.message,
  payload_summary: {
    intent: d._intent,
    confidence: d._confidence,
    risk_level: d._risk_level
  },
  input: d,
  user: d.user,
  risk_context: {
    security_related: d._entities?.security_related || false,
    financial_related: d._entities?.financial_related || false,
    production_related: d._entities?.production_related || false,
    ex_inmetro_related: d._entities?.ex_inmetro_related || false
  },
  retry_count: 0
};
return [{ json: out }];

const d = $input.first().json;
d._selected_agent = "supervisor";
d._selected_workflow = "";
d._routing_reason = "Intent unknown or ambiguous (confidence=" + d._confidence + "). Requesting more info.";
d._policy = d._policy || {};
d._policy.status = "needs_info";
return [{ json: d }];

const downstream = $input.first().json;
const gateway = $('Policy Guard').first().json;

const selected_agent = downstream.agent || gateway._selected_agent || "unknown";
const selected_workflow = downstream.workflow || gateway._selected_workflow || "";
const downstream_status = downstream.status || "success";
const risk_level = downstream.risk_level || gateway._risk_level || "low";
const requires_approval = downstream.requires_approval || gateway._policy?.requires_approval || false;
const approval_id = downstream.approval_id || gateway._policy?.approval_id || null;
const next_action = downstream.next_action || (gateway._policy?.status === "approval_pending" ? "wait_for_approval" : "none");

const out = {
  ...gateway,
  _routing_reason: `Downstream executed: ${selected_workflow} with status ${downstream_status}`,
  _route_message: downstream.summary || downstream.message || "Executed downstream agent",
  _downstream: {
    selected_agent,
    selected_workflow,
    downstream_status,
    downstream_response: downstream,
    risk_level,
    requires_approval,
    approval_id,
    next_action
  }
};
return [{ json: out }];

const d = $input.first().json;
const auditPayload = {
  event_type: "ia.gateway_routed",
  correlation_id: d.correlation_id,
  request_id: d.request_id,
  intent: d._intent,
  selected_agent: d._downstream?.selected_agent || d._selected_agent,
  risk_level: d._downstream?.risk_level || d._risk_level,
  confidence: d._confidence,
  user: d.user,
  source: d.source,
  runtime_mode: d.runtime_mode,
  timestamp: new Date().toISOString()
};
d._audit_log = auditPayload;
return [{ json: d }];

const d = $input.first().json;

let status = d._policy?.status || (d._needs_info ? "needs_info" : "routed");
let requires_approval = d._policy?.requires_approval || false;
let approval_id = d._policy?.approval_id || null;
let risk_level = d._risk_level || "low";
let next_action = status === "routed" ? "execute_agent" :
                 status === "approval_pending" ? "wait_for_approval" :
                 status === "needs_info" ? "request_more_info" :
                 status === "blocked" ? "manual_review" : "none";

let downstream_status = null;
let downstream_response = null;

if (d._downstream) {
  status = d._downstream.downstream_status;
  downstream_status = d._downstream.downstream_status;
  downstream_response = d._downstream.downstream_response;
  requires_approval = d._downstream.requires_approval;
  approval_id = d._downstream.approval_id;
  risk_level = d._downstream.risk_level;
  next_action = d._downstream.next_action;
}

const out = {
  correlation_id: d.correlation_id,
  request_id: d.request_id,
  status: status,
  agent: "supervisor",
  workflow: "CORE - Gateway Supervisor",
  summary: d._routing_reason || "Gateway processed request",
  message: d._route_message || "",
  metadata: d.metadata || {},
  data: {
    intent: d._intent || "unknown",
    confidence: d._confidence || 0,
    selected_agent: d._downstream?.selected_agent || d._selected_agent || "",
    selected_workflow: d._downstream?.selected_workflow || d._selected_workflow || "",
    downstream_status: downstream_status,
    downstream_response: downstream_response,
    risk_level: risk_level,
    requires_approval: requires_approval,
    approval_id: approval_id,
    routing_reason: d._routing_reason || "",
    portal_synced: false,
    entities: d._entities || {}
  },
  missing_fields: d._validation?.missing || [],
  requires_approval: requires_approval,
  approval_id: approval_id,
  risk_level: risk_level,
  next_action: next_action
};

return [{ json: out }];

const err = $input.first().json;
return [{ json: {
  event_type: "ia.gateway_error",
  workflow: "CORE - Gateway Supervisor",
  error: err,
  note: "TODO: Em PORTAL, chamar POST /webhook/vesper/core/error-audit via HTTP Request."
}}];
